@namespace sv_7802cbb3531849248f8f8f072987317b.Components.Pages.Settings

<nav class="settings-sidebar">
    <h5 class="sidebar-title">Settings</h5>
    <ul class="sidebar-nav">
        @foreach (var section in Sections)
        {
            <li class="sidebar-item @(ActiveSection == section ? "active" : "")"
                @onclick="() => OnSectionChanged.InvokeAsync(section)">
                <span class="sidebar-icon">@GetIcon(section)</span>
                <span>@section</span>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

.settings-sidebar {
    width: 220px;
    min-height: 100%;
    border-right: 1px solid #dee2e6;
    padding: 1rem 0;
    background: #f8f9fa;
}

.sidebar-title {
    padding: 0 1.25rem 0.75rem;
    margin: 0;
    font-weight: 600;
    color: #495057;
    font-size: 0.85rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

.sidebar-nav {
    list-style: none;
    padding: 0;
    margin: 0;
}

.sidebar-item {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.65rem 1.25rem;
    cursor: pointer;
    color: #495057;
    font-size: 0.95rem;
    transition: background-color 0.15s, color 0.15s;
    border-left: 3px solid transparent;
}

.sidebar-item:hover {
    background: #e9ecef;
}

.sidebar-item.active {
    background: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 600;
}

.sidebar-icon {
    font-size: 1.1rem;
}

@namespace sv_7802cbb3531849248f8f8f072987317b.Components.Pages.Settings

<div class="profile-section">
    <h4>Profile Settings</h4>

    <div class="avatar-area">
        <img src="@_avatarUrl" alt="Avatar" class="avatar-preview" />
        <div class="avatar-url-display">
            <label class="form-label">Avatar URL</label>
            <input type="text" class="form-control form-control-sm" @bind="_avatarUrl" />
        </div>
    </div>

    <div class="mb-3">
        <label class="form-label">Display Name</label>
        <input type="text" class="form-control" @bind="_displayName" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email</label>
        <input type="email" class="form-control" @bind="_email" />
    </div>

    <div class="mb-3">
        <label class="form-label">Bio</label>
        <textarea class="form-control" rows="4" @bind="_bio"></textarea>
    </div>

    <div class="button-row">
        <button class="btn btn-primary" @onclick="SaveAsync">Save Changes</button>
        <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
    </div>

    @if (_showSuccess)
    {
        <div class="alert alert-success mt-3 fade-in" role="alert">
            ✅ Profile saved successfully!
        </div>
    }
