        {
            var isMuted = _mutedChannels.Contains(channel);
            <div class="form-check channel-item">
                <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                       checked="@isMuted"
                       @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                <label class="form-check-label" for="@($"ch-{channel}")">
                    #@channel
                    @if (isMuted)
                    {
                        <span class="badge bg-secondary ms-1">muted</span>
                    }
                </label>
            </div>
        }
    </div>

    <button class="btn btn-primary mt-3" @onclick="SaveAsync">Save Preferences</button>

