@namespace sv_7802cbb3531849248f8f8f072987317b.Components.Pages.Settings

@if (_showDialog)
{
    <div class="modal-backdrop" @onclick="Cancel">
        <div class="confirm-dialog" @onclick:stopPropagation="true">
            <h5>Revoke Session</h5>
            <p>Are you sure you want to revoke the session on <strong>@_deviceName</strong>?
                This will sign that device out immediately.</p>
            <div class="dialog-buttons">
                <button class="btn btn-outline-secondary" @onclick="Cancel">Cancel</button>
                <button class="btn btn-danger" @onclick="Confirm">Revoke Session</button>
            </div>
        </div>
    </div>
}

@code {
    private bool _showDialog;
    private string _sessionId = "";
    private string _deviceName = "";
    private TaskCompletionSource<bool>? _tcs;

    public Task<bool> ShowAsync(string sessionId, string deviceName)
    {
        _sessionId = sessionId;
        _deviceName = deviceName;
        _showDialog = true;
        _tcs = new TaskCompletionSource<bool>();
        StateHasChanged();
        return _tcs.Task;
    }

    private void Confirm()
    {
        _showDialog = false;
        _tcs?.TrySetResult(true);
    }

    private void Cancel()
    {
        _showDialog = false;
        _tcs?.TrySetResult(false);
    }
}

