@namespace sv_7802cbb3531849248f8f8f072987317b.Components.Pages.Settings

<div class="sessions-table-wrapper">
    <h5>Active Sessions</h5>

    @if (Sessions is null || Sessions.Count == 0)
    {
        <p class="text-muted">No active sessions.</p>
    }
    else
    {
        <table class="table table-hover sessions-table">
            <thead>
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var session in Sessions)
                {
                    var isCurrent = session.Id == CurrentSessionId;
                    <tr>
                        <td>
                            @session.Device
                            @if (isCurrent)
                            {
                                <span class="badge bg-success ms-1">Current</span>
                            }
                        </td>
                        <td>@session.Location</td>
                        <td>@FormatLastActive(session.LastActive)</td>
                        <td>
                            @if (!isCurrent)
                            {
                                <button class="btn btn-sm btn-outline-danger"
                                        @onclick="() => RequestRevoke(session)">
                                    Revoke
                                </button>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    }
</div>

<RevokeSessionDialog @ref="_dialog" />

@code {
    [Parameter] public List<ActiveSession>? Sessions { get; set; }
    [Parameter] public string CurrentSessionId { get; set; } = "sess-1";
    [Parameter] public EventCallback<string> OnRevoke { get; set; }

    private RevokeSessionDialog _dialog = default!;

    private async Task RequestRevoke(ActiveSession session)
    {
        var confirmed = await _dialog.ShowAsync(session.Id, session.Device);
        if (confirmed)
        {
            await OnRevoke.InvokeAsync(session.Id);
        }
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

