@namespace sv_7802cbb3531849248f8f8f072987317b.Components.Pages.Settings

<div class="security-section">
    <h4>Security Settings</h4>

    <ChangePasswordPanel OnChangePassword="HandlePasswordChange" />

    <div class="twofa-section">
        <div class="twofa-row">
            <div>
                <strong>Two-Factor Authentication</strong>
                <div class="text-muted small">Add an extra layer of security to your account</div>
            </div>
            <div class="twofa-status">
                <span class="badge @(TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(TwoFactorEnabled ? "Enabled" : "Disabled")
                </span>
                <div class="form-check form-switch ms-2">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@TwoFactorEnabled"
                           @onchange="e => OnToggleTwoFactor.InvokeAsync((bool)(e.Value ?? false))" />
                </div>
