@namespace sv_7802cbb3531849248f8f8f072987317b.Components.Pages.Settings

<div class="security-section">
    <h4>Security Settings</h4>

    <ChangePasswordPanel OnChangePassword="HandlePasswordChange" />

    <div class="twofa-section">
        <div class="twofa-row">
            <div>
                <strong>Two-Factor Authentication</strong>
                <div class="text-muted small">Add an extra layer of security to your account</div>
            </div>
            <div class="twofa-status">
                <span class="badge @(TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                    @(TwoFactorEnabled ? "Enabled" : "Disabled")
                </span>
                <div class="form-check form-switch ms-2">
                    <input class="form-check-input" type="checkbox" role="switch"
                           checked="@TwoFactorEnabled"
                           @onchange="e => OnToggleTwoFactor.InvokeAsync((bool)(e.Value ?? false))" />
                </div>
            </div>
        </div>

        @if (LastPasswordChange.HasValue)
        {
            <p class="text-muted small mt-2 mb-0">
                Last password change: @LastPasswordChange.Value.ToString("MMMM dd, yyyy")
            </p>
        }
    </div>

    <ActiveSessionsTable Sessions="Sessions" OnRevoke="OnRevokeSession" />
</div>

@code {
    [Parameter] public bool TwoFactorEnabled { get; set; }
    [Parameter] public DateTime? LastPasswordChange { get; set; }
    [Parameter] public List<ActiveSession>? Sessions { get; set; }
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<bool> OnToggleTwoFactor { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private async Task HandlePasswordChange((string Current, string New) args)
    {
        await OnChangePassword.InvokeAsync(args);
    }
}

.security-section {
    max-width: 700px;
}

.twofa-section {
    padding: 1rem;
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    margin-bottom: 1rem;
}

.twofa-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.twofa-status {
    display: flex;
    align-items: center;
}

