@namespace sv_7802cbb3531849248f8f8f072987317b.Components.Pages.Settings

<div class="appearance-section">
    <h4>Appearance Settings</h4>

    <div class="setting-group">
        <h6>Theme</h6>
        <div class="radio-group">
            @foreach (var theme in new[] { "Light", "Dark", "System" })
            {
                <label class="radio-card @(_theme == theme ? "selected" : "")">
                    <input type="radio" name="theme" value="@theme"
                           checked="@(_theme == theme)"
                           @onchange="() => _theme = theme" />
                    <span class="radio-label">@GetThemeIcon(theme) @theme</span>
                </label>
            }
        </div>
    </div>

    <div class="setting-group">
        <h6>Font Size</h6>
        <div class="radio-group">
            @foreach (var size in new[] { "Small", "Medium", "Large" })
            {
                <label class="radio-card @(_fontSize == size ? "selected" : "")">
                    <input type="radio" name="fontSize" value="@size"
                           checked="@(_fontSize == size)"
                           @onchange="() => _fontSize = size" />
                    <span class="radio-label" style="font-size: @GetFontSizeValue(size)">@size</span>
                </label>
            }
        </div>
    </div>

    <div class="setting-group">
        <h6>Language</h6>
        <select class="form-select" style="max-width: 250px;" @bind="_language">
            @foreach (var lang in _languages)
            {
                <option value="@lang">@lang</option>
            }
        </select>
    </div>

    <div class="setting-group">
        <div class="toggle-row">
            <div>
                <strong>Compact Mode</strong>
                <div class="text-muted small">Reduce spacing and padding throughout the UI</div>
            </div>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch"
                       checked="@_compactMode"
                       @onchange="e => _compactMode = (bool)(e.Value ?? false)" />
            </div>
        </div>
    </div>

    <div class="preview-area">
        <h6>Live Preview</h6>
        <div class="preview-card @GetPreviewThemeClass()" style="font-size: @GetFontSizeValue(_fontSize); @(_compactMode ? "padding: 0.5rem;" : "padding: 1.25rem;")">
            <div class="preview-header" style="@(_compactMode ? "margin-bottom: 0.25rem;" : "margin-bottom: 0.75rem;")">
                <strong>Sample Card</strong>
                <span class="preview-badge">Active</span>
            </div>
            <p class="preview-text" style="@(_compactMode ? "margin-bottom: 0.25rem;" : "")">
                This is how your content will look with the selected settings.
                Language: @_language
            </p>
            <div class="preview-actions">
                <span class="preview-button">Action</span>
                <span class="preview-link">Learn more</span>
            </div>
        </div>
    </div>

    <button class="btn btn-primary mt-3" @onclick="SaveAsync">Save</button>

    @if (_showSuccess)
    {
        <div class="alert alert-success mt-3 fade-in" role="alert">
            ✅ Appearance settings saved!
        </div>
    }
</div>

